const ACTIVE_TTL_MS = 7200000;
const RECOVERED_TTL_MS = 14400000;
const FLAPPING_EXTENDED_TTL_MS = VMID_REDACTED;
const CLOSED_COOLDOWN_MS = 300000;
const FLAP_ESCALATE_THRESHOLD = 2;

if (Object.keys(sd.activeAlerts).length === 0) {
  const sshOut = sshData.stdout || '';
  if (sshOut.trim() && sshOut.trim() !== '{}') {
    try {
      const loaded = JSON.parse(sshOut.trim());
      if (loaded && typeof loaded === 'object' && !Array.isArray(loaded)) {
        sd.activeAlerts = loaded;
      }
    } catch(e) {}
  }
}

if (body.action === 'register' && body.alertKey && body.issueId) {
  const entry = sd.activeAlerts[body.alertKey];
