    entry.issueId = body.issueId;
    entry.registeredAt = Date.now();
  } else {
    sd.activeAlerts[body.alertKey] = {
      issueId: body.issueId, registeredAt: Date.now(),
      firstSeen: Date.now(), lastSeen: Date.now(), count: 1, flapCount: 0
    };
