  let shouldEscalate = false;
  let flapCount = 0;

  if (isAlert) {
    if (sd.closedAlerts[alertKey]) {
      if (Date.now() - sd.closedAlerts[alertKey] < CLOSED_COOLDOWN_MS) {
        continue;
      } else {
        delete sd.closedAlerts[alertKey];
      }
    }

    const entry = sd.activeAlerts[alertKey];
    if (entry) {
      existingIssueId = entry.issueId || '';
      entry.lastSeen = Date.now();
