      if (entry.recoveredAt) {
        entry.flapCount = (entry.flapCount || 0) + 1;
        delete entry.recoveredAt;
      }
      flapCount = entry.flapCount || 0;

      if (existingIssueId) {
        isRepeat = true;
        repeatAction = 'check_yt';
        commentText = 'Alert re-fired: ' + alertname + ' in ' + namespace +
          ' at ' + new Date().toISOString() + ' (count: ' + entry.count +
          (flapCount > 0 ? ', flap #' + flapCount : '') + ')';

