          const lastEsc = entry.lastEscalatedAt || 0;
          if (now - lastEsc >= 3600000) {
            shouldEscalate = true;
            entry.lastEscalatedAt = now;
          } else {
            shouldEscalate = false;
            commentText += ' (escalation cooldown \u2014 last escalated ' + Math.round((now - lastEsc) / 60000) + 'min ago)';
          }
        }
      } else {
        if (entry.firstSeen && (Date.now() - entry.firstSeen < CREATION_LOCK_MS)) {
          continue;
        }
        isRepeat = false;
        sd.activeAlerts[alertKey] = {
          issueId: null, firstSeen: Date.now(), lastSeen: Date.now(),
          count: 1, flapCount: entry.flapCount || 0
        };
