  if (isAlert && !sd.currentBurst.fired && sd.currentBurst.alerts.length >= BURST_THRESHOLD) {
    isBurst = true;
    sd.currentBurst.fired = true;
    burstAlertKeys = sd.currentBurst.alerts.join(',');
    const nsSet = new Set(sd.currentBurst.alerts.map(k => k.split(':').slice(1).join(':')));
    burstNamespaces = [...nsSet].join(',');
  }

  const flapLabel = flapCount > 0 ? ' [FLAPPING x' + flapCount + ']' : '';
  const escalateLabel = shouldEscalate ? ' \u2b06\ufe0f ESCALATING' : '';
  const emoji = isRecovery ? '\u2705' : (severity === 'critical' ? '\ud83d\udd34' : '\ud83d\udfe1');
  const stateLabel = isRecovery ? 'RESOLVED' : 'ALERT';

  const plainBody = emoji + ' [Prometheus] ' + stateLabel + ': ' + alertname +
    ' (' + severity + ')' + flapLabel + escalateLabel + '\n' +
    'Namespace: ' + namespace + '\n' +
    (pod ? 'Pod: ' + pod + '\n' : '') +
    (hostname ? 'Node: ' + hostname + '\n' : '') +
    'Summary: ' + summary;

  const htmlBody = '<b>' + emoji + ' [Prometheus] ' + stateLabel + ':</b> ' + alertname +
    ' (<code>' + severity + '</code>)' +
    (flapCount > 0 ? ' <b>[FLAPPING x' + flapCount + ']</b>' : '') +
    (shouldEscalate ? ' <b>\u2b06\ufe0f ESCALATING</b>' : '') + '<br/>' +
    'Namespace: ' + namespace + '<br/>' +
    (pod ? 'Pod: <code>' + pod + '</code><br/>' : '') +
    (hostname ? 'Node: <code>' + hostname + '</code><br/>' : '') +
    'Summary: ' + summary;

  const alertsB64 = Buffer.from(JSON.stringify(sd.activeAlerts)).toString('base64');

  results.push({
    json: {
      alertname: safeAlertname, severity, namespace: safeNamespace, pod: safePod,
      hostname: safeNode, summary: safeSummary, isRecovery, isAlert, stateLabel,
      alertKey, plainBody, htmlBody,
      matrixBody: JSON.stringify({
        msgtype: isRecovery ? 'm.notice' : 'm.text',
        body: plainBody, format: 'org.matrix.custom.html', formatted_body: htmlBody
      }),
      shouldTriage, shouldEscalate, hasContent: true, isRepeat, existingIssueId,
      repeatAction, commentText, alertsB64, isLastRecovery, flapCount,
      isBurst, burstAlertKeys, burstNamespaces,
      expiredRecoveryIssues: expiredRecoveryIssueIds.join(',')
    }
  });
}

if (results.length === 0) {
  const alertsB64 = Buffer.from(JSON.stringify(sd.activeAlerts)).toString('base64');
  return [{ json: { hasContent: false, alertsB64, isBurst: false, burstAlertKeys: '',
    burstNamespaces: '', expiredRecoveryIssues: '' } }];
}

return results;

const parseAlert = $('Parse Alerts').first().json;
const ytResponse = $input.first().json;

let repeatAction = 'comment';
let ytState = 'unknown';

try {
  const customFields = ytResponse.customFields || [];
  const stateField = customFields.find(f => f.name === 'State');
  if (stateField && stateField.value) {
    ytState = stateField.value.name || 'unknown';
  }
} catch(e) {
  ytState = 'unknown';
}

if (!ytResponse.id && !ytResponse.idReadable) {
  repeatAction = 'new';
} else if (ytState === 'Done' || ytState === 'Cancelled' || ytState === 'Duplicate') {
  repeatAction = 'new';
  const sd = $getWorkflowStaticData('global');
  if (sd.activeAlerts && sd.activeAlerts[parseAlert.alertKey]) {
    sd.activeAlerts[parseAlert.alertKey].issueId = null;
  }
} else if (ytState === 'To Verify') {
  repeatAction = 'reopen';
} else {
  repeatAction = 'comment';
}

const shouldEscalate = parseAlert.shouldEscalate || false;
const flapCount = parseAlert.flapCount || 0;

return [{ json: { ...parseAlert, repeatAction, ytState, shouldEscalate, flapCount } }];
